class Solution:
    def canMakePalindromeQueries(self, s: str, queries: List[List[int]]) -> List[bool]:
        n = len(s)
        odd_count = 0
        for i in range(n // 2):
            if s[i] != s[n - i - 1]:
                odd_count += 1
        answer = []
        for a, b, c, d in queries:
            left_odd_count = 0
            right_odd_count = 0
            for i in range(a, b + 1):
                if s[i] != s[n - i - 1]:
                    left_odd_count += 1
            for i in range(c, d + 1):
                if s[i] != s[n - i - 1]:
                    right_odd_count += 1
            if left_odd_count <= odd_count // 2 and right_odd_count <= odd_count // 2:
                answer.append(True)
            else:
                answer.append(False)
        return answer
```

